   //  To Delete the Account 
   public deleteLink(Identity identity, Link link) {
    try {
      if (null != identity &&null != link) {
        ProvisioningPlan plan = new ProvisioningPlan();
        AccountRequest acctReq = new AccountRequest();
        acctReq.setNativeIdentity(link.getNativeIdentity());
        acctReq.setApplication(link.getApplicationName());
        acctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Delete);
        plan.add(acctReq);
        plan.setIdentity(identity);
        Provisioner p = new Provisioner(context);
        p.execute(plan);
      }
    } catch (Exception e) {
      plog.trace("AADRL-LW-001:: Exception occured while deleting account from adhoc " + e.getMessage());
    }
  }

  // Get attributes to remove from Application Form passed in section
  public List getAttributesToRemoveFromForm(Application application,List attributesToRemove,String sectionName) {
    Form form = application.getProvisioningForm( Form.Type.Create , "account" );
    if ( form != null) {
      Section sectionInvite = form.getSection(sectionName);
      if (sectionInvite == null) {
        if (form.getFormRef() != null) {
          String formRefName = form.getFormRef().getName();
          plog.trace( "AADRL-LW-002 :: Account Reference Form Name in "+sectionName+ " Section : " + formRefName );
          if (Util.isNotNullOrEmpty(formRefName)) {
            Form accountForm = context.getObjectByName(Form.class,formRefName);
            if (accountForm != null) {
              sectionInvite = accountForm.getSection(sectionName);
              if (sectionInvite != null) {
                for ( Field field : sectionInvite.getFields() ) {
                  attributesToRemove.add( field.getName() );
                }
              }
            }
          }
        }
      } else{
        for ( Field field : sectionInvite.getFields() ) {
          attributesToRemove.add( field.getName() );
        }
      }
      plog.trace( "AADRL-LW-003 :: Removing Invite attributes: " + attributesToRemove.toString() );
      plog.trace( "AADRL-LW-004 :: Removing Non-Invite attributes List: " + attributesToRemove);
    }
    return attributesToRemove;
  }
   //workflow launch to send the prehire email notificaiton
   public void launchWorkflow(String identityName,String wfName,String caseName,Map args){
    if ( plog.isTraceEnabled() ) {
        plog.trace("AADRL-LW-005 :: Entering launchWorkflow()");
        plog.trace("AADRL-LW-006 :: identityName::"+identityName+"|caseName::"+caseName+"|wfName::"+wfName);
    }
    HashMap launchArgs = new HashMap();
    launchArgs.put("identityName",identityName);
    launchArgs.put("launcher","spadmin");
    if(args != null){
      launchArgs.putAll(args);
    }
    WorkflowLaunch wfLaunch = new WorkflowLaunch();
    Workflow workflow = (Workflow)context.getObjectByName(Workflow.class,wfName);
    if(null != workflow){
      wfLaunch.setWorkflowName(workflow.getName());
      wfLaunch.setWorkflowRef(workflow.getName());
      wfLaunch.setCaseName(caseName+" : "+identityName); 
      wfLaunch.setVariables(launchArgs);
      Workflower workflower = new Workflower(context);
      WorkflowLaunch Launch = workflower.launch(wfLaunch);
      if ( plog.isTraceEnabled() ) {
        plog.trace("AADRL-LW-007 :: Launched "+wfName);
      }
    }
    if ( plog.isTraceEnabled() ) {
      plog.trace("AADRL-LW-008 :: Exiting launchWorkflow()"); 
    }
   }

  /**
  * updateGuestPrehireAccountAttribute updates the guest account attributes while create account.
  * creation where Native Identity is required before it exists.
  * @param context The SailPointContext Object
  * @param accountRequest The current AccountRequest Object to be examined
  * @param application The Application Object being evaluated
  * @param identity The Identity Object being evaluated
  */
  public static void updateGuestPrehireAccountAttribute( SailPointContext context, AccountRequest accountRequest, Application application, Identity identity ) {
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AADRL-LW-009 ::Entering Azure AD Rule Library - updateGuestPrehireAccountAttribute" );
    }
    if ( accountRequest != null ) {
      AttributeRequest EntAttrReq = accountRequest.getAttributeRequest("groups");
      if ( null != EntAttrReq ) {
        Object entValueObject = EntAttrReq.getValue();
        Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure AD Guest Account" );
        if(null != extensionAttributesCustomObject){
          preHireGroupValue = extensionAttributesCustomObject.getString( "preHireGroupNameForAzureADTMNA");
          if(entValueObject instanceof String){
            if (null != preHireGroupValue && entValueObject != null && entValueObject.equalsIgnoreCase(preHireGroupValue)) {
              AttributeRequest inviteUserEmailAttrReq = accountRequest.getAttributeRequest("invitedUserEmailAddress");
              AttributeRequest inviteRedirectUrlAttrReq = accountRequest.getAttributeRequest("inviteRedirectUrl");
              inviteUserEmailAttrReq. setValue(getIdentityAttribute( context, identity, "PersonalEmail" ));
              inviteRedirectUrlAttrReq. setValue(getAzureADTMNAURL( identity ));
            }
           } else if(entValueObject instanceof List){
              if (null != preHireGroupValue && entValueObject != null && entValueObject.contains(preHireGroupValue)) {
                AttributeRequest inviteUserEmailAttrReq = accountRequest.getAttributeRequest("invitedUserEmailAddress");
                AttributeRequest inviteRedirectUrlAttrReq = accountRequest.getAttributeRequest("inviteRedirectUrl");
                inviteUserEmailAttrReq. setValue(getIdentityAttribute( context, identity, "PersonalEmail" ));
                inviteRedirectUrlAttrReq. setValue(getAzureADTMNAURL( identity ));
            }
          }
        }
      }
    }
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AADRL-LW-010 ::Leaving Azure AD Rule Library - updateGuestPrehireAccountAttribute" );
    }
  }

   /**
  *
  * This method will get workday application from the identity
  *
  */
  public String getWorkdayAppNamefromIdentityLink(String identityName){
    String wAppName = null;
    if(null != identityName){
      Filter filter = Filter.and(Filter.eq("identity.name",identityName),Filter.ignoreCase(Filter.eq("application.type","Workday")));
      QueryOptions qo = new QueryOptions();
      qo.addFilter(filter);
      Iterator linksIterator = context.search(Link.class, qo);
      while (linksIterator.hasNext()) {
        Link link = (Link) linksIterator.next();
        wAppName = link.getApplicationName();
      }
      Util.flushIterator( linksIterator );
    }
    return wAppName;
  }

  /*******
    Determine Azure AD TMA URL if the user is having preHireIdentificationFlag as true then it will return Guest User URL else in other case it will return as User URL.
      1) Normal Azure User
      2) Guest Azure User
   *******/ 
  public String getAzureADTMNAURL( Identity identity ) {
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AADRL-LW-011 ::Entering Azure AD Rule Library - getAzureADTMNAURL" );
    }
    String responseString = "";
    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure AD Guest Account" );
    if ( extensionAttributesCustomObject != null ) {
      String userUrl=extensionAttributesCustomObject.get("userUrl");
      String guestUserUrl=extensionAttributesCustomObject.get("preHireAcceptInviteUrl");    
      String preHireFlag = identity.getAttribute("preHireIdentificationFlag");
    if(null != preHireFlag && "true".equalsIgnoreCase(preHireFlag)){   
      responseString = guestUserUrl;
    }else{
      responseString = userUrl;
    }
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AADRL-LW-012 :: Identity: " + identity.getName() + " :: " + responseString );
      plog.trace( "AADRL-LW-013 :: Leaving Azure AD Rule Library - getAzureADTMNAURL" );
    }
  }
    return responseString;
  }

  /*******
  Internal method to get Azure Access token for Graph API Calls
  *******/
  public String getAccessToken( String azureADDomain, String resource, String clientID, String clientSecret ) throws Exception {

    HttpClient httpclient = HttpClients.createDefault();
    String accessToken = "";

    String url = "https://login.microsoft.com/" + azureADDomain + "/oauth2/v2.0/token";
    HttpPost post = new HttpPost(url);
    List nameValuePairs = new ArrayList(5);
    nameValuePairs.add( new BasicNameValuePair( "scope", "https://graph.microsoft.com/.default" ) );
    nameValuePairs.add( new BasicNameValuePair( "client_id", clientID ) );
    nameValuePairs.add( new BasicNameValuePair( "client_secret", clientSecret ) );
    nameValuePairs.add( new BasicNameValuePair( "aud", "https://graph.microsoft.com/" ) );
    nameValuePairs.add( new BasicNameValuePair( "grant_type", "client_credentials" ) );
    nameValuePairs.add( new BasicNameValuePair( "tenant", azureADDomain ) );
    post.setEntity( new UrlEncodedFormEntity( nameValuePairs ) );
    HttpResponse response = httpclient.execute( post );
    HttpEntity entity = response.getEntity();

    if (entity != null) {
      String content = EntityUtils.toString( entity );
      JSONObject obj = new JSONObject( content );
      accessToken = obj.getString( "access_token" );
    }
    return accessToken;
  }


   /**
  * createAzureADMTMGuestUser Removes attributeRequest based on accountType. If the accountType is "User". It will remove guest releated attriuteRequest from the plan and vice-versa.
  * creation where Native Identity is required before it exists.
  * @param accountRequest The current AccountRequest Object to be examined
  * @param application The Application Object being evaluated
  * @param identity The Identity Object being evaluated
  */
  public void createAzureADMTMGuestUser(AccountRequest accountRequest, Application application, Identity identity) {

    String identityType = identity.getType()!=null?identity.getType():"";
    String userEmail = identity.getEmail()!=null?identity.getEmail():"";
    if ( plog.isTraceEnabled() ) {
      plog.trace( "Email: " + userEmail );
    }

    String userType = "Member";
    List attributesToRemove = new ArrayList();
    AttributeRequest accountTypeAttrReq = accountRequest.getAttributeRequest( "accountType" );
    if ( accountTypeAttrReq != null ) {
      accountType = accountTypeAttrReq.getValue().toString();
      if ( accountType.equalsIgnoreCase( "user" )) {
        plog.trace( "Azure User or Guest User account. Remove Invitation attributes." );
        // Get attributes to remove from Application Form Guest B2B section
        attributesToRemove = getAttributesToRemoveFromForm(application,attributesToRemove,"GuestUser");

        // Determine what kind of user account
        if ( identityType.equalsIgnoreCase( "supplier" ) ) {
          userType = "Guest";
        }
        accountRequest.add( new ProvisioningPlan.AttributeRequest( "userType", ProvisioningPlan.Operation.Add, userType ) );
      } else {
        plog.trace( "Guest B2B User. Remove Non-Invitation attributes." );
        attributesToRemove = getAttributesToRemoveFromForm(application,attributesToRemove,"User");

        // Add Guest userType
        userType = "Guest";
        accountRequest.add( new ProvisioningPlan.AttributeRequest( "userType", ProvisioningPlan.Operation.Add, userType ) );
      }

      // Remove Attributes
      List attributeRequests = accountRequest.getAttributeRequests();
      if ( plog.isTraceEnabled() ) {
        plog.trace( "Attribute Request List: " + attributeRequests.toString() );
        plog.trace( "Attribute Request Size: " + attributeRequests.size().toString() );
      }

      List attributeRequestsToRemove = new ArrayList();
      if (attributeRequests !=null && !attributeRequests.isEmpty()) {
        for ( ProvisioningPlan.AttributeRequest attreq : attributeRequests ) {
          String attributeName = attreq.getName().toString();
          if ( plog.isTraceEnabled() ) {
            plog.trace( "Working with Attribute: " + attributeName );
          }

          if ( attributesToRemove.contains( attributeName ) ) {
            plog.trace( "Getting Attribute to Remove: " + attributeName );
            attributeRequestsToRemove.add( attreq );
          }
        }
      }
      if ( plog.isTraceEnabled() ) {
        plog.trace( "Attribute Removal List: " + attributeRequestsToRemove.toString() );
        plog.trace( "Attribute Removal Size: " + attributeRequestsToRemove.size().toString() );
      }
      if ( attributeRequestsToRemove != null && attributeRequestsToRemove.size() > 0 ) {
        // remove the attributes now
        for ( ProvisioningPlan.AttributeRequest attributeRemoval : attributeRequestsToRemove ) {
          plog.trace( " Removing Attribute: " + attributeRemoval.getName().toString() );
          accountRequest.remove( attributeRemoval );
        }
      }
    } else {
      toyotaLogger( context, "Account Type is Null for Method: createAzureADMTMGuestUser" );
    }

  }

  /*******
    Determine Azure AD MTM User Type if the user is having preHireIdentificationFlag as true and azure ad mtm member accout then it will return Guest User B2B else in other case it will return as User.
      1) Normal Azure User
      2) Guest Azure User
  *******/  
  public String getAzureADMTMUserType( SailPointContext context, Application application, Identity identity ) {
    plog.trace( "Entering Azure AD Rule Library - getAzureADMTMUserType" );
    String user="User";
    String guestUser="Guest User B2B";
    String responseString = "";

    IdentityService identityService = new IdentityService(context);
    List links =  identityService.getLinks( identity, application );
    if(null != links && !links.isEmpty()){
      for(Link link : links ){
        String preHireFlag = identity.getAttribute("preHireIdentificationFlag");
        String userType = link.getAttribute("userType");
        if(null != preHireFlag && null != userType && "Member".equalsIgnoreCase(userType) && "true".equalsIgnoreCase(preHireFlag)){
          responseString = guestUser;
          break;
        }else{
          responseString = user;
          break;
        }
      }
    }else{
      responseString = user;
    }
    plog.trace( "User Type for Identity: " + identity.getName() + " :: " + responseString );
    plog.trace( "Leaving Azure AD Rule Library - getAzureADMTMUserType" );

    return responseString;
  }

   /*******
    Determine Azure AD MTM URL if the user is having preHireIdentificationFlag as true then it will return Guest User URL else in other case it will return as User URL.
      1) Normal Azure User
      2) Guest Azure User
   *******/ 
  public String getAzureADMTMURL( Identity identity, Application application ) {

    plog.trace( "Entering Azure AD Rule Library - getAzureADMTMURL" );
    String userUrl=application.getAttributeValue("AzureADMTMUserUrl");
    String guestUserUrl=application.getAttributeValue("AzureADMTMGuestUserUrl");
    String responseString = "";
    String preHireFlag = identity.getAttribute("preHireIdentificationFlag");
    if(null != preHireFlag &&  "true".equalsIgnoreCase(preHireFlag)){   
      responseString = guestUserUrl;
    }else{
      responseString = userUrl;
    }
    plog.trace( "Identity: " + identity.getName() + " :: " + responseString );
    plog.trace( "Leaving Azure AD Rule Library - getAzureADMTMURL" );

    return responseString;
  }

  /*******
  Search Azure for existance of email
  *******/
  public String isAzureEmailPresent( SailPointContext context, Application app, Identity identity, String email ) throws Exception {

    plog.trace( "AADRL-ISAEP-01 Entering Azure AD Rule Library - isAzureEmailPresent" );
    String azureADDomain = (String)app.getAttributeValue( "domainName" );
    String clientID = (String)app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)app.getAttributeValue( "clientSecret" ) );
    String resource = "https://graph.microsoft.com/beta/users";
    plog.trace( "AADRL-ISAEP-02 isAzureemailPresent email" +email );
    HttpClient httpclient = HttpClients.createDefault();
    String[] mailparts=email.split( "@" );
    String emailprefix = mailparts[0];
    String emaildomain= mailparts[1];
    String mailEA2Check = null;
    String guidAttributeName = "";


    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    if ( extensionAttributesCustomObject != null ) {
      guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    } else {
      plog.trace( "AADRL-ISAEP-03 ERROR:: Cannot find Azure Extension Attributes Object" );
    }

    String url = resource+"?$select="+guidAttributeName+",id,mail&"+ "$filter="+ URLEncoder.encode( "mail eq ", "UTF-8" )+ "'"+ URLEncoder.encode( emailprefix, "UTF-8")+ "@" + emaildomain+ URLEncoder.encode( "' or otherMails/any(id:id eq '","UTF-8")+URLEncoder.encode( emailprefix, "UTF-8")+ "@" + emaildomain+ "')";
    plog.trace( "AADRL-ISAEP-04 EncodedURL : " + url);
    String accessToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    plog.trace( "AADRL-ISAEP-05 Access Token:\n" + accessToken + "\n" );
    HttpGet request = new HttpGet(url);
    request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
    request.setHeader(HttpHeaders.AUTHORIZATION, accessToken );
    HttpResponse response = httpclient.execute( request );
    int statuscode = response.getStatusLine().getStatusCode();

    if ( statuscode >= 200 && statuscode < 300 ) {
      HttpEntity entity = response.getEntity();

      if (entity != null) {
        String content = EntityUtils.toString( entity );
        plog.trace( "AADRL-ISAEP-06 Response content: " + content );
        plog.trace( "AADRL-ISAEP-07 Response Type: " + content.getClass() );
        JSONObject obj = new JSONObject( content );

        if( obj.getJSONArray("value").length() > 0 ) {
          mailpresent=true;
          if ( plog.isTraceEnabled() ) {
            plog.trace( "AADRL-ISAEP-08 Object Type: " + obj.getClass() );
          }
          JSONArray azureUserArray = obj.getJSONArray( "value" );

          if ( plog.isTraceEnabled() ) {
            plog.trace( "AADRL-ISAEP-09 azureUserArray: \n" + azureUserArray.toString() );
          }
          JSONObject azureUser = azureUserArray.get(0);
          String azureEA2 = null;
          String userObjectID = null;

          if(azureUser.has("id")){
            userObjectID = azureUser.get( "id" ).toString();
            plog.trace("AADRL-ISAEP-10 userObjectID : "+userObjectID);
          }
          if(azureUser.has(guidAttributeName)){
            azureEA2 = azureUser.get( guidAttributeName ).toString();
            plog.trace("AADRL-ISAEP-11 azureEA2 : "+azureEA2);
          }
          String idenGUID = identity.getAttribute("guid");
          plog.trace("AADRL-ISAEP-12 idenGUID : "+idenGUID);

          if(azureEA2 == null){
            plog.trace("AADRL-ISAEP azureEA2 is null entered if condition");
            plog.trace("AADRL-ISAEP-1 GUID in Azure AD is :"+azureEA2+" and in Sailpoint is "+idenGUID+ " for the user "+identity.getName());
            Boolean myResult = updateUserGUID( identity, userObjectID, accessToken );
            mailEA2Check = "RemoveAccountReq:EmailFoundGUIDUpdated";
          } else {
            if(idenGUID != null && !idenGUID.equalsIgnoreCase(azureEA2)){
              mailEA2Check = "GuestAccount";
              plog.trace("AADRL-ISAEP-13 idenGUID not null And idenGUID not equals of azureEA2");
              plog.trace("AADRL-ISAEP-13.1 GUID in Azure AD is :"+azureEA2+" and in Sailpoint is "+idenGUID+ " for the user "+identity.getName());
              plog.trace("AADRL-ISAEP-13.2 email address in Sailpoint is:"+email);
            } else {
              mailEA2Check = "RemoveAccountReq:Aggregation";
              plog.trace("AADRL-ISAEP-14 idenGUID null OR idenGUID  equals of azureEA2");
              plog.trace("AADRL-ISAEP-14.1 GUID in Azure AD is :"+azureEA2+" and in Sailpoint is "+idenGUID+ " for the user "+identity.getName());
            }
          }
        }
      }
    }
    plog.trace( "AADRL-ISAEP-15 - Leaving Azure AD Rule Library - isAzureEmailPresent" + mailEA2Check );

      return mailEA2Check;
  }

  /*******
  getting ObjectID from azure based on the users  email address.
  *******/
  public String getAzureObjectIdUsingMail( SailPointContext context, Application app, Identity identity, String email ) throws Exception {

    plog.trace( "AADRL-GAOIDUM-01 Entering Azure AD Rule Library - getAzureObjectIdUsingMail" );
    String azureADDomain = (String)app.getAttributeValue( "domainName" );
    String clientID = (String)app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)app.getAttributeValue( "clientSecret" ) );
    String resource = "https://graph.microsoft.com/v1.0/users";
    plog.trace( "AADRL-GAOIDUM-02 isAzureemailPresent email " +email );
    HttpClient httpclient = HttpClients.createDefault();
    String[] mailparts=email.split( "@" );
    String emailprefix = mailparts[0];
    String emaildomain= mailparts[1];
    String guestUserObjectId = null;
    String guidAttributeName = "";

    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    if ( extensionAttributesCustomObject != null ) {
      guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    } else {
      plog.trace( "AADRL-GAOIDUM-03 ERROR:: Cannot find Azure Extension Attributes Object" );
    }

    String url = resource+"?$select="+guidAttributeName+",id,mail,creationType&"+ "$filter="+ URLEncoder.encode( "mail eq ", "UTF-8" )+ "'"+ URLEncoder.encode( emailprefix, "UTF-8")+ "@" + emaildomain+ "'";
    plog.trace( "AADRL-GAOIDUM-04 EncodedURL : " + url);
    String accessToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    plog.trace( "AADRL-GAOIDUM-05 Access Token:\n" + accessToken + "\n" );
    HttpGet request = new HttpGet(url);
    request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
    request.setHeader(HttpHeaders.AUTHORIZATION, accessToken );
    HttpResponse response = httpclient.execute( request );
    int statuscode = response.getStatusLine().getStatusCode();

    if ( statuscode >= 200 && statuscode < 300 ) {
      HttpEntity entity = response.getEntity();
      if (entity != null) {
        String content = EntityUtils.toString( entity );
        plog.trace( "AADRL-GAOIDUM-06 Response content: " + content );
        plog.trace( "AADRL-GAOIDUM-07 Response Type: " + content.getClass() );
        JSONObject obj = new JSONObject( content );
        if( obj.getJSONArray("value").length() > 0 ) {
          mailpresent=true;
          plog.trace( "AADRL-GAOIDUM-08 Object Type: " + obj.getClass() );
          JSONArray azureUserArray = obj.getJSONArray( "value" );
          plog.trace( "AADRL-GAOIDUM-09 azureUserArray: \n" + azureUserArray.toString() );
          JSONObject azureUser = azureUserArray.get(0);
          String azureEA2 = null;
          String userObjectID = null;
          String creationType = null;
          if(azureUser.has("id")){
            userObjectID = azureUser.get( "id" ).toString();
            plog.trace("AADRL-GAOIDUM-10 userObjectID : "+userObjectID);
          }
          if(azureUser.has(guidAttributeName)){
            azureEA2 = azureUser.get( guidAttributeName ).toString();
            plog.trace("AADRL-GAOIDUM-11 azureEA2 : "+azureEA2);
          }
          if(azureUser.has("creationType")){
            creationType = azureUser.get( "creationType" ).toString();
            plog.trace("AADRL-GAOIDUM-11.1 creationType : "+creationType);
          }
          String idenGUID = identity.getAttribute("guid");
          plog.trace("AADRL-GAOIDUM-12 idenGUID : "+idenGUID);
          if(azureEA2 != null && idenGUID != null && !idenGUID.equalsIgnoreCase(azureEA2) && creationType.equalsIgnoreCase("Invitation")){
            guestUserObjectId = userObjectID;
            Boolean myResult = updateUserGUID( identity, userObjectID, accessToken );
            plog.trace("AADRL-GAOIDUM-13 idenGUID not null And idenGUID not equals of azureEA2");
          }
          else if (azureEA2 != null && idenGUID != null && idenGUID.equalsIgnoreCase(azureEA2)){
            guestUserObjectId = userObjectID;
            plog.trace("AADRL-GAOIDUM-13 idenGUID not null And idenGUID not equals of azureEA2");
          }
        } 
      }
    }
    plog.trace( "AADRL-GAOIDUM-15 - Leaving Azure AD Rule Library - getAzureObjectIdUsingMail" + guestUserObjectId );

    return guestUserObjectId;
  }

  /*******
  Update User GUID in Azure
  *******/
  public Boolean updateUserGUID( Identity identity, String objectId, String accessToken ) {
    plog.trace( "Entering Azure AD Rule Library - updateUserGUID" );
    String guidAttributeName = "";
    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    if ( extensionAttributesCustomObject != null ) {
      guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    } else {
      plog.trace( "ERROR:: Cannot find Azure Extension Attributes Object" );
      return false;
    }
    String resource = "https://graph.microsoft.com/beta/users/";
    String userGUID = identity.getAttribute( "guid" ) != null ? identity.getAttribute( "guid" ) : "";
    plog.trace( "GUID: " + userGUID );
    HttpClient httpclient = HttpClients.createDefault();
    Boolean success = false;
    String url = resource + objectId;
    if ( plog.isTraceEnabled() ) {
      plog.trace( "EncodedURL : " + url );
    }
    if (Util.isNotNullOrEmpty(userGUID)) {
      JSONObject entensionAttribute = new JSONObject();
      entensionAttribute.put( "extensionAttribute2", userGUID );
      JSONObject payload = new JSONObject();
      payload.put( "onPremisesExtensionAttributes", entensionAttribute );
      payload.put( guidAttributeName, userGUID );
      plog.trace( "JSON Payload:\n\n" + payload.toString() + "\n\n" );
      StringEntity body = new StringEntity( payload.toString() );
      HttpPatch request = new HttpPatch( url );
      request.setHeader( HttpHeaders.CONTENT_TYPE, "application/json" );
      request.setHeader( HttpHeaders.AUTHORIZATION, accessToken );
      request.setEntity( body );
      HttpResponse response = httpclient.execute( request );
      int statuscode = response.getStatusLine().getStatusCode();
      plog.trace( "Status Code " + statuscode );

      if ( statuscode >= 200 && statuscode < 300 ) {
        plog.trace( "Status Reason: " + response.getStatusLine().getReasonPhrase() );
        success = true;
        HttpEntity entity = response.getEntity();
        if (entity != null) {
          String stuff = EntityUtils.toString( entity );
          if ( plog.isTraceEnabled() ) {
            plog.trace( "Status Code: " + stuff );
          }
        }
      }
      plog.trace( "Leaving Azure AD Rule Library - updateUserGUID" );
    }
    return success;
  }

  /*******
    Determine Azure User Type
      1) Normal Azure User
      2) Guest Azure User
      3) B2B Guest Invite User
  *******/
  public String getAzureADUserType( SailPointContext context, Application application, Identity identity ) {

    plog.trace( "Entering Azure AD Rule Library - getAzureADUserType" );
    QueryOptions qo=new QueryOptions();
    String user="User";
    String guestB2BUser="Guest User B2B";
    String responseString = "";
    boolean isRetired = false;

    IdentityService idService = new IdentityService(context);
    Application appObject = context.getObjectByName(Application.class,"Workday TMNA");
    if(identity != null && appObject != null ) {
      List linkList = idService.getLinks(identity,appObject);
      if ( Util.nullSafeSize(linkList) > 0 ){
        Link link = linkList.get(0);
        String linkAttr = link.getAttribute("IS_RETIRED");
        if(Util.nullSafeEq(linkAttr, "1")) {
          isRetired = true;
        }
        context.decache(appObject);
      }
    }

  // This is used to support the guest account creation for the prehire.
    String preHireFlag = identity.getAttribute("preHireIdentificationFlag");
    String companycode = identity.getAttribute("companyCode");
    if(null != preHireFlag && "true".equalsIgnoreCase(preHireFlag) ){
      IdentityService identityService = new IdentityService(context);
      List links =  identityService.getLinks( identity, application );
      if(null != links && !links.isEmpty()){
        for(Link link : links ){

          String userType = link.getAttribute("userType");
          if( null != userType && "Member".equalsIgnoreCase(userType)){
            responseString = guestB2BUser;
          }
        }
      }
      if(Util.isNullOrEmpty(responseString) && null != companycode ){
        if("TCC".equalsIgnoreCase(companycode) || 
        "TIS".equalsIgnoreCase(companycode) || 
        "TFB".equalsIgnoreCase(companycode) || 
        "TPR".equalsIgnoreCase(companycode) || 
        "BJN".equalsIgnoreCase(companycode) || 
        "BTR".equalsIgnoreCase(companycode) || 
        "TCA".equalsIgnoreCase(companycode) || 
        "TIN".equalsIgnoreCase(companycode) || 
        "TKY".equalsIgnoreCase(companycode) || 
        "TMP".equalsIgnoreCase(companycode) || 
        "TTX".equalsIgnoreCase(companycode) || 
        "TAL".equalsIgnoreCase(companycode) || 
        "TNC".equalsIgnoreCase(companycode) || 
        "TWV".equalsIgnoreCase(companycode) || 
        "AIR".equalsIgnoreCase(companycode) || 
        "TDP".equalsIgnoreCase(companycode) || 
        "TLS".equalsIgnoreCase(companycode) || 
        "TMN".equalsIgnoreCase(companycode) || 
        "TMS".equalsIgnoreCase(companycode) || 
        "TNA".equalsIgnoreCase(companycode) || 
        "TRD".equalsIgnoreCase(companycode)){
          responseString = guestB2BUser;
        }
      }
    }

  if(null == responseString || responseString.isEmpty()){
     String userEmail = identity.getEmail();
      if ( userEmail != null && !userEmail.isEmpty() ) {
        Filter filter = Filter.and( Filter.eq( "application", application ), Filter.eq( "appMail", userEmail ) );
        qo.addFilter( filter );
    // This reduces overhead in the call by not returning complete identity objects
      ArrayList colsToRead = new ArrayList();
      colsToRead.add("appMail");
      Iterator it = context.search( Link.class, qo, colsToRead );
      if ( (null != it) && (it.hasNext()) ) {
        plog.trace("Identities Matched by email");
        plog.trace("AccountType User entered");
        responseString = user;
        if ( isRetired ) responseString = guestB2BUser;
      } else {
        Map domainMails = application.getAttributeValue( "emailDomainNames" );
        if ( domainMails != null && !domainMails.isEmpty() && userEmail.contains("@") ) {
          String [] emails= userEmail.split("@");
          String emailDomain = "";
          if (emails.length > 1 && emails[1]!= null){
            emailDomain = emails[1];
          }
          if ( domainMails.containsKey( emailDomain ) ) {
            plog.trace("AccountType User entered");
            responseString = user;
            if ( isRetired ) responseString = guestB2BUser;
          } else {
            plog.trace("AccountType Guest entered");
            responseString = guestB2BUser;
          }
        } else {
          // Default to Guest
          plog.trace("AccountType Guest entered");
          responseString = guestB2BUser;
        }
      }
      Util.flushIterator(it);
    } else {
      String userUPN = identity.getAttribute( "userPrincipalName" );
      if ( userUPN != null && !userUPN.isEmpty() ) {
        String [] upns= userUPN.split("@");
        String upnDomain = "";
        if (upns.length > 1 && upns[1]!= null){
          upnDomain = upns[1];
        }
        Map domainMails = application.getAttributeValue( "emailDomainNames" );
        if ( domainMails != null && !domainMails.isEmpty() ) {
          if ( domainMails.containsKey( upnDomain ) ) {
            responseString = user;
            if ( isRetired ) responseString = guestB2BUser;
          } else {
            responseString = guestB2BUser;
          }
        }
      } else {
        toyotaLogger( context, "User: " + identity.getName() + " Missing Email and UPN.  Cannot provision " + application.getName() );
      }
    }
  }
    plog.trace( "User Type for Identity: " + identity.getName() + " :: " + responseString );
    plog.trace( "Leaving Azure AD Rule Library - getAzureADUserType" );

    return responseString;
  }

  /*******
  Get Azure AD UPN ( userPrincipalName )
  *******/
  public String getAzureADUPN( SailPointContext context, Application application, Identity identity ) {

    plog.trace( "Entering Azure AD Rule Library - getAzureADUPN" );

    Custom supplierConfiguration;
    String userName = identity.getName();
    String userType = identity.getType()!=null?identity.getType():"";
    String userEmail = identity.getEmail()!=null?identity.getEmail():"";
    String appDomain;
    String uPN="";

    try {
      supplierConfiguration = context.getObjectByName(Custom.class, "Supplier Configuration");
      appDomain = supplierConfiguration.get("domainSuffix");
    } catch ( Exception ex ) {
      plog.trace( "ERROR :: Exception fetching Custom Object: " + ex.toString() );
      return null;
    }

    if ( !(userType.equalsIgnoreCase( "supplier" ) || userType.equalsIgnoreCase( "marketing" )) ) { //  Everyone but not suppliers and Marketing users
      plog.trace( "AZRL-GAADUON-002:: Regular User UPN (email or UPN)" );
      uPN = getEmailOrUPN( context, identity );
    } 
    else if (userType.equalsIgnoreCase( "marketing" )){
      if ( userName.indexOf( "@" ) != -1 && !userName.split( "@" )[1].equalsIgnoreCase( application.getAttributeValue("toyotaMarketingDomain") )) { // username with @
        // email address outside of toyota for usernames
        if ( !userName.split( "@" )[1].equalsIgnoreCase( application.getAttributeValue("toyotaMarketingDomain") ) ) {
          appDomain = userName.split( "@" )[1];
        }
        uPN = userName.split( "@" )[0] + "@" + appDomain;
      } else { // username without @
        plog.error("AZRL-GAADUON-003:: ERROR :: Supplier User Invalid Username: " + userName);
        uPN = userName;
      }
    }
    else {  // All Suppliers
      plog.trace( "AZRL-GAADUON-004:: Supplier User UPN (Guest User or Guest B2B Invite" );
      if ( userName.indexOf( "@" ) != -1 ) { // username with @
        // email address outside of toyota for usernames
        if ( !userName.split( "@" )[1].equalsIgnoreCase( "toyotasupplier.com" ) ) {
          appDomain = userName.split( "@" )[1];
        }
        uPN = userName.split( "@" )[0] + "@" + appDomain;
      } else { // username without @
        plog.error("AZRL-GAADUON-005:: ERROR :: Supplier User Invalid Username: " + userName);
        uPN = userName;
      }
    }
    if ( plog.isTraceEnabled() ) {
      if ( Util.isNullOrEmpty( uPN ) ) {
        plog.trace( "AZRL-GAADUON-006:: UPN for Identity: " + identity.getName() + " :: null" );
      } else {
        plog.trace( "AZRL-GAADUON-007:: UPN for Identity: " + identity.getName() + " :: " + uPN );
      }
      plog.trace( "AZRL-GAADUON-008:: Leaving Azure AD Rule Library - getAzureADUPN" );
    }
    return uPN;
  }

    /*******
  Get Azure AD PIM UPN ( userPrincipalName )
  *******/
  public String getAzureAdPIMUPN( SailPointContext context, Application application, Identity identity ) {
    plog.trace( "AZRL ::001::UPNPIM::Start" );
    String appDomain = application.getAttributeValue("domainSuffix");
    String userName = identity.getName();
    String userEmail = identity.getEmail()!=null?identity.getEmail():"";
    String uPN="";
    String MSAvalue = application.getAttributeValue("azureADPrivAccountPrefix");

    if ( userName != null ) {
       plog.trace( "Regular User UPN" );
       uPN = MSAvalue+"-"+userName + "@" + appDomain;
     }
     else {
      toyotaLogger( context, "AZRL012::User: " + userName + " UserType is empty/null");
    }
     if ( plog.isTraceEnabled() ) {
        plog.trace( "AZRL::UPN PIM 002 for Identity: " + identity.getName() + " :: " + uPN );
        plog.trace( "AZRL::UPN PIM 003 Leaving Azure AD Rule Library - getAzureAdPIMUPN" );
     }
     return uPN;
  }
