  /*******
  Clean Duplicate SailPoint Account Link for single Azure user
  This Link is created when an attempt is made to invite 2 different
  email addresses that are mail aliases to the same user in a
  different Azure tennant

  The Link must be deleted so that we can create the user as a guest
  *******/
  public Boolean cleanDuplicateAccountLink( SailPointContext context, String linkNativeIdentity, Identity currentIdentity ) {

    plog.trace( "AZRL-CDAL-01::Entering Azure AD Rule Library - cleanDuplicateAccountLink" );
    String appName = "Azure AD";
    Boolean response = false;
    String linkToDelete = "";
    Application app = context.getObjectByName( Application.class, appName );
    QueryOptions qo = new QueryOptions();
    qo.add( new Filter[] { Filter.and( Filter.eq( "application", app ), Filter.ignoreCase( Filter.eq( "nativeIdentity", linkNativeIdentity ) ) ) } );
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AZRL-CDAL-02::Created Filter for search" );
    }
    int matchedLinks = context.countObjects( Link.class, qo );
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AZRL-CDAL-03::Matched links: " + matchedLinks );
    }

    // More than one match means that the same account is linked to more than one Identity.
    Iterator it = context.search( Link.class, qo );
    plog.trace( "AZRL-CDAL-04::More than 1 result.  Got Search results" );
    if ( it != null ) {
      while ( it.hasNext() ) {
        Link link = it.next();
        Identity linkIdentity = link.getIdentity();
        String linkGUID = linkIdentity.getAttribute( "guid" );
        String currentIdentityGUID = currentIdentity.getAttribute( "guid" );
        if ( linkGUID != null && currentIdentityGUID != null ) {
          // Delete the link for the Identity we just provisioned
          if ( linkGUID.equalsIgnoreCase( currentIdentityGUID ) ) {
            linkToDelete = link.getId();
            plog.trace( "AZRL-CDAL-05::Deleting Link: " + linkToDelete + " for Identity: " + linkIdentity.getName() );
          } else {
            plog.trace( "AZRL-CDAL-06::NOT Deleting Link: " + linkToDelete + " for Identity: " + linkIdentity.getName() );
          }
        } else {
          plog.trace( "AZRL-CDAL-07::ERROR:: One GUID is NULL" );
        }
      }
      sailpoint.tools.Util.flushIterator( it );
      plog.trace( "AZRL-CDAL-08::Flushed Iterator" );
      if ( !linkToDelete.isEmpty() ) {
        Terminator t = new Terminator( context );

        Link deleteLink = context.getObjectById( Link.class, linkToDelete );
        try {
          plog.trace( "AZRL-CDAL-09::Deleting Account: " + deleteLink.getNativeIdentity() );
          t.deleteObject( deleteLink );
          plog.trace( "AZRL-CDAL-10::Deleted" );
          response = true;
        } catch ( Exception ex ) {
          plog.trace( "AZRL-CDAL-11::ERROR:: " + ex.toString() );
        }
      }
    }
    plog.trace( "AZRL-CDAL-12::Exiting Azure AD Rule Library - cleanDuplicateAccountLink" );

    return response;
  }

