  /*******
  Check for Crosslinked account
  *******/
  public Boolean isAccountCrosslinked( SailPointContext context, Application application, Identity identity, String azureIDCreated ) {

    plog.trace( "AZRL-ISACL-01::Entering Azure AD Rule Library - isAccountCrosslinked" );
    String azureADDomain = (String)application.getAttributeValue( "domainName" );
    String clientID = (String)application.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)application.getAttributeValue( "clientSecret" ) );
    String resource = "https://graph.microsoft.com/beta/users";
    HttpClient httpclient = HttpClients.createDefault();
    Boolean result = false;
    String guidAttributeName = "";
    // Get extension attribute names from the custom object
    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    if ( extensionAttributesCustomObject != null ) {
      guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    } else {
      plog.trace( "AZRL-ISACL-02::ERROR:: Cannot find Azure Extension Attributes Object" );
      return false;
    }

    String azureUserGUID = "";
    String identityGUID = identity.getAttribute( "guid" );
    if ( identityGUID == null || identityGUID.isEmpty() ) {
      plog.trace( "AZRL-ISACL-02::User: " + identity.getName() + " missing GUID" );
    }

    String accessToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    String url = resource + "/" + azureIDCreated + "?$select=" + guidAttributeName;
    plog.trace( "AZRL-ISACL-03::Request URL: " + url );
    HttpGet request = new HttpGet(url);
    request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
    request.setHeader(HttpHeaders.AUTHORIZATION, accessToken );
    HttpResponse response = httpclient.execute( request );
    int statuscode = response.getStatusLine().getStatusCode();

    if ( statuscode >= 200 && statuscode < 300 ) {
      HttpEntity entity = response.getEntity();

      if (entity != null) {
        String content = EntityUtils.toString( entity );
        plog.trace( "AZRL-ISACL-04::Response content: " + content );
        plog.trace( "AZRL-ISACL-05::Response Type: " + content.getClass() );

        JSONObject obj = new JSONObject( content );

        if ( obj.has( guidAttributeName ) ) {
          azureUserGUID = obj.getString( guidAttributeName );
          if ( azureUserGUID != null && !azureUserGUID.isEmpty() ) {
            plog.trace( "AZRL-ISACL-06::Response GUID: " + azureUserGUID );
            plog.trace( "AZRL-ISACL-07::Identity GUID: " + identityGUID + "\n\n" );

            if ( !azureUserGUID.equalsIgnoreCase( identityGUID ) ) {
              result = true;
            }
          } else {
            plog.trace( "AZRL-ISACL-08::No GUID returned" );
          }
        }
      }
    }
    plog.trace( "AZRL-ISACL-09::Leaving Azure AD Rule Library - isAccountCrosslinked" );

    return result;
  }


  //Create Azure GuestUser Scenario
  public Boolean createAzureGuestUser(SailPointContext context, AccountRequest accountRequest, Application application, Identity identity) {

    String identityType = identity.getType()!=null?identity.getType():"";
    String email = identity.getEmail()!=null?identity.getEmail():"";
    String userEmail;
    AttributeRequest userEmailAttrReq = accountRequest.getAttributeRequest( "invitedUserEmailAddress");
    if (userEmailAttrReq != null && userEmailAttrReq.getValue() != null) {
       userEmail = userEmailAttrReq.getValue().toString()!=null ? userEmailAttrReq.getValue().toString() : email;
    }
    else 
    {
      userEmail = email;   
    }
    plog.trace( "AADRL-CAGU-01: Email: " + userEmail );
    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    String guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    String accountType;
    String userType = "Member";
    List attributesToRemove = new ArrayList();
    AttributeRequest isCrossLinked = accountRequest.getAttributeRequest( "crossLinked" );
    AttributeRequest isSharedAzureTenantEmails = accountRequest.getAttributeRequest( "sharedAzureTenantEmails" );
    AttributeRequest accountTypeAttrReq = accountRequest.getAttributeRequest( "accountType" );
    Boolean linkedExistingAccount = false;

    if ( accountTypeAttrReq != null ) {
      accountType = accountTypeAttrReq.getValue().toString();
      plog.trace( "AADRL-CAGU-02 :Working with accountType: " + accountType );

      //  Determine if this guest should be created or linked
      try {
        String mailEA2AzureCheck;
        if ( Util.isNotNullOrEmpty( userEmail ) ) {
          mailEA2AzureCheck = isAzureEmailPresent( context, application, identity, userEmail );
        }
        if ( mailEA2AzureCheck != null ) {
          if(mailEA2AzureCheck.equalsIgnoreCase("GuestAccount")){
            plog.trace( "AADRL-CAGU-03 :User email " + userEmail + " found in Azure---"+mailEA2AzureCheck );
            if(accountType != null && accountType.equalsIgnoreCase("Guest User B2B")){
              accountRequest.remove(accountTypeAttrReq);
              accountRequest.add(new ProvisioningPlan.AttributeRequest( "accountType", ProvisioningPlan.Operation.Set, "User" ) );
              accountType = "User";
            }
          } else if(mailEA2AzureCheck.equalsIgnoreCase("RemoveAccountReq:EmailFoundGUIDUpdated")){
            linkedExistingAccount = true;
            plog.trace( "AADRL-CAGU-04 User email " + userEmail + " found in Azure and Linked---"+mailEA2AzureCheck );
          } else if(mailEA2AzureCheck.equalsIgnoreCase("RemoveAccountReq:Aggregation")){
            linkedExistingAccount = true;
            plog.trace( "AADRL-CAGU-05 User email " + userEmail + " found in Azure and Linked---"+mailEA2AzureCheck );
          }
          // Link Account

        } else {
          // New Invite
          plog.trace( "AADRL-CAGU-06 User email " + userEmail + " NOT found in Azure" );
        }
      } catch ( Exception ex ) {
        toyotaLogger( context, "AADRL-CAGU-07 An error occurred with searching Azure:: " + ex.toString() );
      }

      if ( isSharedAzureTenantEmails != null ) {
        plog.trace( "AADRL-CAGU-08 Azure Tenant Shares Email Domains" );
        accountType = "User";
        attributesToRemove.add( "sharedAzureTenantEmails" );
        attributesToRemove.add( "accountType" );
      }

      if ( accountType.equalsIgnoreCase( "user" ) || isCrossLinked != null ) {
        if ( !accountType.equalsIgnoreCase( "user" )) {
          attributesToRemove.add( "accountType" );
        }
        plog.trace( "AADRL-CAGU-09 Azure User or Guest User account. Remove Invitation attributes." );

        // Get attributes to remove from Application Form Guest B2B section
        attributesToRemove = getAttributesToRemoveFromForm(application,attributesToRemove,"Guest User B2B");

        // Determine what kind of user account
        if ( identityType.equalsIgnoreCase( "supplier" ) || identityType.equalsIgnoreCase( "marketing" )) {
          userType = "Guest";
        }
        accountRequest.add( new ProvisioningPlan.AttributeRequest( "userType", ProvisioningPlan.Operation.Add, userType ) );

      } else {
        plog.trace( "AADRL-CAGU-10 Guest B2B User. Remove Non-Invitation attributes." );
        attributesToRemove = getAttributesToRemoveFromForm(application,attributesToRemove,"User");

        //adding the following attributes to remove from the AccountRequest
        attributesToRemove.add("firstName");
        attributesToRemove.add("lastName");
        attributesToRemove.add("email");
        attributesToRemove.add("userType");
      }
      // Never provision GUID except for supplier users and toyotamarketing users
      if ( !(identityType.equalsIgnoreCase( "supplier" ) || identityType.equalsIgnoreCase( "marketing" )) ) {

        if ( !attributesToRemove.contains( guidAttributeName ) ) {
          attributesToRemove.add( guidAttributeName );
        }

        if ( !attributesToRemove.contains( "extensionAttribute2" ) ) {
          attributesToRemove.add( "extensionAttribute2" );
        }
      }
      // Remove Attributes
      List attributeRequests = accountRequest.getAttributeRequests();
      plog.trace( "AADRL-CAGU-11 Attribute Request List: " + attributeRequests.toString() );
      plog.trace( "AADRL-CAGU-12 Attribute Request Size: " + attributeRequests.size().toString() );
      List attributeRequestsToRemove = new ArrayList();
        if (attributeRequests !=null && !attributeRequests.isEmpty()) {
          for ( ProvisioningPlan.AttributeRequest attreq : attributeRequests ) {
            String attributeName = attreq.getName().toString();
            if ( plog.isTraceEnabled() ) {
              plog.trace( "AADRL-CAGU-13 Working with Attribute: " + attributeName );
            }

          if ( attributesToRemove.contains( attributeName ) ) {
            plog.trace( "AADRL-CAGU-13.1 Getting Attribute to Remove: " + attributeName );
            attributeRequestsToRemove.add( attreq );
          }
        }
      }
      plog.trace( "AADRL-CAGU-14 Attribute Removal List: " + attributeRequestsToRemove.toString() );
      plog.trace( "AADRL-CAGU-15 Attribute Removal Size: " + attributeRequestsToRemove.size().toString() );
      if ( attributeRequestsToRemove != null && attributeRequestsToRemove.size() > 0 ) {
        // remove the attributes now
        for ( ProvisioningPlan.AttributeRequest attributeRemoval : attributeRequestsToRemove ) {
          plog.trace( "AADRL-CAGU-16 Removing Attribute: " + attributeRemoval.getName().toString() );
          accountRequest.remove( attributeRemoval );
        }
      }
      if ( attributeRequestsToRemove != null && attributeRequestsToRemove.contains( "crossLinked" ) ) {
        accountRequest.add( new ProvisioningPlan.AttributeRequest( "accountType", ProvisioningPlan.Operation.Add, "User" ) );
      }
      if ( attributeRequestsToRemove != null && attributeRequestsToRemove.contains( "sharedAzureTenantEmails" ) ) {
        accountRequest.add( new ProvisioningPlan.AttributeRequest( "accountType", ProvisioningPlan.Operation.Add, "User" ) );
      }
    } else {
       toyotaLogger( context, "AADRL-CAGU-17 Account Type is Null for Method: createAzureGuestUser" );
    }
    return linkedExistingAccount;
  }

  //Azure AD Update User Scenario
  public Boolean updateAzureUser(SailPointContext context, ProvisioningPlan plan, AccountRequest accrst , Application application, Identity identity) throws Exception{

    plog.trace( "AADRL-UAZU-01::Entering AzureAD-RuleLibrary - updateAzureUser" );
    plog.trace( "AADRL-UAZU-02::Inside Modify Method:::" );

    Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
    String guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    String primarySupplierNumber = extensionAttributesCustomObject.getString( "primarySupplierNumber" );
    String emailAttributeName = extensionAttributesCustomObject.getString( "emailSupplier" );
    plog.trace( "AADRL-UAZU-03::emailAttributeName::: "+emailAttributeName );
    ProvisioningPlan deletePlan = new ProvisioningPlan();
    List azureOtherMail=new ArrayList();
    AttributeRequest attrReq = new AttributeRequest();
    attrReq = accrst.getAttributeRequest(emailAttributeName);
    IdentityService identityService = new IdentityService(context);
    List links =  identityService.getLinks( identity, application );
    Boolean linkedAccount = false;
    if (attrReq!=null && links != null && links.size()>=1) {
      if ( plog.isTraceEnabled() ) {
        plog.trace( "AADRL-UAZU-04::emailAttributeName attrReq::: "+attrReq.toXml() );
      }
      String newMail=attrReq.getValue();
      plog.trace( "AADRL-UAZU-05::application*****:: "+application );
      plog.trace( "AADRL-UAZU-06::newMail*****:: "+newMail );
      Link azureLink = links.get(0);
      if(azureLink!=null) {
        String azureExtEmail=azureLink.getAttribute(emailAttributeName);
        if ( plog.isTraceEnabled() ) {
          plog.trace( "AADRL-UAZU-07::azureLink*****:: "+azureLink.toXml()+" azureExtEmail***:: "+azureExtEmail );
        }
        //Checking if this a Attribute Synchronization scenario
        if(azureExtEmail!=null && !azureExtEmail.equalsIgnoreCase( newMail ) )
        {
          String azureUPN = azureLink.getAttribute("userPrincipalName");
          if ( plog.isTraceEnabled() ) {
            plog.trace( "AADRL-UAZU-08::azureUPN*****:: "+azureUPN );
            plog.trace( "AADRL-UAZU-09::Inside Suppliers and mail update::: attribute req::: "+attrReq.toXml()+" :: AzureUPN::: "+azureUPN );
          }
          //Checking if the identity is the Guest User
          if(azureUPN.contains("#EXT#"))
          {
            plog.trace("AADRL-UAZU-10::newMail inside If and above delete::: "+newMail);
            plog.trace("AADRL-UAZU-11::Inside Invited User::: "+azureUPN );
            //Deleting the already existing Guest Azure account
            deletePlan.setIdentity(identity);
            AccountRequest delAccReq = new AccountRequest();
            delAccReq.setOperation(AccountRequest.Operation.Delete);
            delAccReq.setNativeIdentity(accrst.getNativeIdentity());
            delAccReq.setApplication("Azure AD");
            deletePlan.add(delAccReq);

            //Extract the groups to be added back if the user is an external user
            List groupsToAddBack = new ArrayList();
            String creationType = azureLink.getAttribute("creationType");
            if( Util.isNotNullOrEmpty(identity.getType()) && Util.nullSafeCaseInsensitiveEq(creationType,"Invitation"))
            {
              List linkGroups = azureLink.getAttribute("groups");
              if(null!=linkGroups && linkGroups.size()>0)
              {
                for(String groupId:linkGroups)
                {
                  List filters = new ArrayList();
                  filters.add(Filter.eq("value", groupId));
                  filters.add(Filter.eq("attribute", "groups"));
                  filters.add(Filter.eq("application.name", "Azure AD"));
                  Filter filter = Filter.and(filters);
                  ManagedAttribute azureEntitlement = context.getUniqueObject(ManagedAttribute.class, filter);
                  if(azureEntitlement!=null && azureEntitlement.isRequestable()==true)
                  {
                    groupsToAddBack.add(groupId);
                  }
                }
              }
            }// End preparation of groups add Back

            if ( plog.isTraceEnabled() ) {
              plog.trace( "AADRL-UAZU-12::Delete plan::: "+deletePlan.toXml() );
            }
            Provisioner p = new Provisioner(context);
            p.execute(deletePlan);
            plog.trace( "AADRL-UAZU-13::Delete the existing account::: " );
            //Checking if the Sailpoint identity exists with the same mail and with Azure account  to decide the AccountType
            Filter f = Filter.eq("email", newMail);
            plog.trace("AADRL-UAZU-14::newMail::: "+newMail);
            f = Filter.and(f, Filter.eq("links.application.name", application.getName()));
            QueryOptions ops = new QueryOptions();
            ops.addFilter(f);
            int identityObjs = context.countObjects(Identity.class, ops);
            //Works for AccountType User
            if(identityObjs > 0) {
              plog.trace( "AADRL-UAZU-15::Inside AccountType User:::" );
              accrst.setOperation(ProvisioningPlan.AccountRequest.Operation.Create);
              accrst.add(new ProvisioningPlan.AttributeRequest("accountType", ProvisioningPlan.Operation.Add, "User"));
              if ( plog.isTraceEnabled() ) {
                plog.trace( "AADRL-UAZU-16::AccountReq after adding AccountType User--- "+accrst.toXml());
              }
            } else {
              //Works for AccountType Guest User B2B
              plog.trace( "AADRL-UAZU-17::Inside AccountType Guest User B2B:::" );
              accrst.setOperation(ProvisioningPlan.AccountRequest.Operation.Create);
              accrst.add(new ProvisioningPlan.AttributeRequest("accountType", ProvisioningPlan.Operation.Add, "Guest User B2B"));
              accrst.add(new ProvisioningPlan.AttributeRequest("invitedUserEmailAddress", ProvisioningPlan.Operation.Set,newMail));
              accrst.add(new ProvisioningPlan.AttributeRequest(emailAttributeName, ProvisioningPlan.Operation.Set,newMail));
              if(groupsToAddBack.size()>0)
              {
                accrst.add(new ProvisioningPlan.AttributeRequest("groups",ProvisioningPlan.Operation.Set,groupsToAddBack));
              }
              if ( plog.isTraceEnabled() ) {
                plog.trace( "AADRL-UAZU-18::AccountReq after adding AccountType B2B--- "+accrst.toXml());
              }
            }
            //Fetching the attributes for Create operation from Project Expansion Items
            Provisioner provisioner=new Provisioner (context);
            ProvisioningProject project=provisioner.compile(plan);
            if ( plog.isTraceEnabled() ) {
              plog.trace("AADRL-UAZU-19::ProvisioningProject------"+project.toXml());
            }
            List expansionItems=project.getExpansionItems();
            List attributeRequests=new ArrayList();
            List formAttributesList=new ArrayList();
            for(AttributeRequest planattributes: accrst.getAttributeRequests()) {
              attributeRequests.add(planattributes.getName());
            }
            for(ExpansionItem expansionItem : expansionItems) {
              //Avoiding duplicate Attribute Requests
              if(!attributeRequests.contains(expansionItem.getName())) {
                AttributeRequest attrReqAdded=new ProvisioningPlan.AttributeRequest(expansionItem.getName(), ProvisioningPlan.Operation.Set, expansionItem.getValue());
                accrst.add(attrReqAdded);
                if ( plog.isTraceEnabled() ) {
                  plog.trace("AADRL-UAZU-20::attrReqAdded From Expansion Item------"+attrReqAdded.toXml());
                }
              }
            }

            if ( plog.isTraceEnabled() ) {
              plog.trace("AADRL-UAZU-21::FinalAccountReq Before Create------"+accrst.toXml());
            }
            linkedAccount = createAzureGuestUser(context, accrst, application, identity);
          } else {
            //If the identity is not the Azure Guest user
            plog.trace( "AADRL-UAZU-22::Inside Old Guest Account not a B2B:::" );
            azureOtherMail = azureLink.getAttribute("otherMails");
            if(azureOtherMail!=null) {
              if(azureLink.getAttribute(emailAttributeName)!=null && azureOtherMail.contains(azureLink.getAttribute(emailAttributeName))) {
                plog.trace( "AADRL-UAZU-23::Extension email::: "+azureLink.getAttribute(emailAttributeName) );
                azureOtherMail.remove(azureLink.getAttribute(emailAttributeName));
                azureOtherMail.add(newMail);
              } else {
                plog.trace( "AADRL-UAZU-24::Extension email else::: "+azureLink.getAttribute(emailAttributeName) );
                azureOtherMail.clear();
                azureOtherMail.add(newMail);
              }

              plog.trace( "AADRL-UAZU-25::Other email:::"+azureOtherMail );
              accrst.add(new AttributeRequest("otherMails",ProvisioningPlan.Operation.Set,azureOtherMail));
              if ( plog.isTraceEnabled() ) {
                plog.trace( "AADRL-UAZU-26::Plan not guest::: "+plan.toXml() );
              }
            }
          }
        }
      }
    }
    return linkedAccount;
  }

 /***
  Set Extension Attributes
  ***/
  public Boolean setExtensionAttributes(SailPointContext context, Application app, String extensionAttribute, String extensionAttributeValue, String azureID) {

    String azureADDomain = (String)app.getAttributeValue( "domainName" );
    String clientID = (String)app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)app.getAttributeValue( "clientSecret" ) );
    String resource = "https://graph.microsoft.com/beta/users/";
    String accessToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    String url = resource + azureID + "/";
    plog.trace("AADRL-SEA-01::Update URL: "+url);


    HttpClient httpclient = HttpClients.createDefault();
    Boolean result = false;

    if (Util.isNotNullOrEmpty(extensionAttributeValue)) {
      JSONObject entensionAttribute = new JSONObject();
      entensionAttribute.put( extensionAttribute, extensionAttributeValue );

      JSONObject payload = new JSONObject();
      payload.put( "onPremisesExtensionAttributes", entensionAttribute );
      plog.trace( "AADRL-SEA-02::JSON Payload:\n\n" + payload.toString() + "\n\n" );
      StringEntity body = new StringEntity( payload.toString() );
      HttpPatch request = new HttpPatch( url );
      request.setHeader( HttpHeaders.CONTENT_TYPE, "application/json" );
      request.setHeader( HttpHeaders.AUTHORIZATION, accessToken );
      request.setEntity( body );
      HttpResponse response = httpclient.execute( request );
      int statuscode = response.getStatusLine().getStatusCode();

      plog.trace( "AADRL-SEA-02::Status Code " + statuscode );

      if ( statuscode >= 200 && statuscode < 300 ) {
        plog.trace( "AADRL-SEA-03::Status Reason: " + response.getStatusLine().getReasonPhrase() );
        result = true;

        HttpEntity entity = response.getEntity();

        if (entity != null) {
          String stuff = EntityUtils.toString( entity );
          plog.trace( "AADRL-SEA-04::Status Code: " + stuff );
        }
      }
    }
    return result;
  }

