  /*******
  Search Azure for existance of multiple mailNicknames
  *******/
  public Object isAzureMailNicknamePresent( SailPointContext context, Application app, TreeMap mailNicknameHash ) {

    plog.trace( "AADRL-ISAMNMP-01::Entering Azure AD Rule Library - isAzureMailNicknamePresent" );
    List usedMailNicknames = new ArrayList();
    String nicknameFilters = "";
    String azureADDomain = (String)app.getAttributeValue( "domainName" );
    String clientID = (String)app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)app.getAttributeValue( "clientSecret" ) );
    String resource = "https://graph.microsoft.com/beta/users";

    plog.trace( "AADRL-ISAMNMP-02::azureADDomain: " + azureADDomain );
    plog.trace( "AADRL-ISAMNMP-03::clientID:      " + clientID );
    plog.trace( "AADRL-ISAMNMP-04::clientSecret:  " + clientSecret );
    plog.trace( "AADRL-ISAMNMP-05::resource:      " + resource );


    HttpClient httpclient = HttpClients.createDefault();
    Boolean mailpresent=false;

    for ( Map.Entry entry : mailNicknameHash.entrySet() ) {
      nicknameFilters = nicknameFilters
      + "(proxyAddresses/any(x:startswith(x,'smtp:"
      + entry.getValue()
      + "@')))"
      + "or"
      + "(startswith(userPrincipalName,'"
      + entry.getValue()
      + "@'))"
      + "or";
    }

    nicknameFilters = nicknameFilters.substring( 0, nicknameFilters.length() - 2 );

    String url = resource
      + "?$filter=(("
      + URLEncoder.encode( "userType eq ", "UTF-8" )
      + "'Member')and("
      + nicknameFilters
      + "))&select=proxyAddresses,userPrincipalName";
    plog.trace( "AADRL-ISAMNMP-06::EncodedURL : " + url);
    String accessToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    plog.trace( "AADRL-ISAMNMP-07::Access Token:\n" + accessToken + "\n" );
    HttpGet request = new HttpGet(url);
    request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
    request.setHeader(HttpHeaders.AUTHORIZATION, accessToken );
    HttpResponse response = httpclient.execute( request );
    int statuscode = response.getStatusLine().getStatusCode();
    if ( statuscode >= 200 && statuscode < 300 ) {
      HttpEntity entity = response.getEntity();
      if (entity != null) {
        String content = EntityUtils.toString( entity );
          plog.trace( "AADRL-ISAMNMP-08::Response content: " + content );
          plog.trace( "AADRL-ISAMNMP-09::Response Type: " + content.getClass() );

        JSONObject obj = new JSONObject( content );

        if( obj.getJSONArray("value").length() > 0 ) {
          mailpresent=true;
          plog.trace( "AADRL-ISAMNMP-10::Object Type: " + obj.getClass() );
          JSONArray azureUsers = obj.getJSONArray( "value" );
          if ( azureUsers != null ) {
            for ( int i = 0 ; i < azureUsers.length() ; i++ ) {
              JSONObject userJSON = azureUsers.get( i );
              String userPrincipalName = userJSON.get( "userPrincipalName" );
              if ( userPrincipalName != null && !userPrincipalName.isEmpty() ) {
                usedMailNicknames.add( userPrincipalName.split( "@" )[ 0 ] );
              }
              JSONArray proxyAddesses = userJSON.getJSONArray( "proxyAddresses" );
              for ( int j = 0 ; j < proxyAddesses.length() ; j++ ) {
                String proxyAddress = proxyAddesses.get( j );
                if ( proxyAddress != null && !proxyAddress.isEmpty() ) {
                  usedMailNicknames.add( proxyAddress.split( ":" )[ 1 ].split( "@" )[ 0 ] );
                }
              }
            }
          }
          plog.trace( "AADRL-ISAMNMP-11::azureUser: \n" + azureUsers.toString() );
          plog.trace( "AADRL-ISAMNMP-12::Response JSON:\n\n" + userObjectID + "\n\n" );
        }
      }
    }
    return usedMailNicknames;
  }

  /*******
  Determine if Azure Invitation Message should be sent
  *******/
  public String sendInviteMessage( SailPointContext context, Application app, Identity identity ) {

    plog.trace( "AADRL-SIM-01::Entering Azure AD Rule Library - sendInviteMessage" );
    Map inviteMessages = new HashMap();
    String sendInvite = "false";
    String userEmail = identity.getEmail();
    if ( userEmail !=null && !userEmail.isEmpty() ) {
      inviteMessages = application.getAttributeValue( "invitedUserMessages" );
      String userType = identity.getType();
      if ( inviteMessages != null && userType != null && !inviteMessages.isEmpty()  && userType.length() > 0) {
        if ( inviteMessages.containsKey( userType ) ) {
          if ( userType.equalsIgnoreCase( "external" ) ) {
            IdentityService idSvc = new IdentityService( context );
            Application application = context.getObjectByName( Application.class,"eVehicle External" );
            if ( null != application ) {
              List links = idSvc.getLinks( identity,application );
              if ( links != null && links.size() == 1 ) {
                sendInvite = "true";
              }
            }
          }
          else {
            sendInvite = "true";
          }
        }
      }
    }
    plog.trace( "AADRL-SIM-02::Leaving Azure AD Rule Library - sendInviteMessage" );
    return sendInvite;
  }

  /*******
  Get Azure Invitation Message
  *******/
  public String getAzureInviteMessage( SailPointContext context, Application app, Identity identity ) {

    plog.trace( "AADRL-GAIM-01::Entering Azure AD Rule Library - getAzureInviteMessage" );
    Map inviteMessages = new HashMap();
    Map invitePrimaryMessages = new HashMap();
    String inviteMessage = "";
    inviteMessages = application.getAttributeValue( "invitedUserMessages" );
    invitePrimaryMessages = application.getAttributeValue( "invitedPrimaryUserMessages" );
    String userType = identity.getType();

    List subTypeList = new ArrayList();
    Object subTypeObj = identity.getAttribute("subType");
    if(subTypeObj != null){
      if(subTypeObj instanceof List){
        subTypeList = subTypeObj;
      } else if(subTypeObj instanceof String){
        subTypeList.add(subTypeObj);
      }
    }
    if ( inviteMessages != null && userType != null && !inviteMessages.isEmpty()  && userType.length() > 0 && !subTypeList.contains("TDEM")) {
      if ( inviteMessages.containsKey( userType ) ) {
        if ( userType.equalsIgnoreCase( "external" ) ) {
          IdentityService idSvc = new IdentityService( context );
          Application application = context.getObjectByName( Application.class,"eVehicle External" );
          if ( null != application ) {
            List links = idSvc.getLinks( identity,application );
            if ( links != null && links.size() == 1 ) {
              inviteMessage = inviteMessages.get( userType );
            }
          }
        }
        else {
          inviteMessage = inviteMessages.get( userType );
        }
      }
    }
    else if ( invitePrimaryMessages != null && userType != null && !invitePrimaryMessages.isEmpty()  && userType.length() > 0 && subTypeList.contains("TDEM")) {
      if ( invitePrimaryMessages.containsKey( userType ) ) {
        inviteMessage = invitePrimaryMessages.get( userType );
      }
    }
    plog.trace( "AADRL-GAIM-02::Leaving Azure AD Rule Library - getAzureInviteMessage" );

    return inviteMessage;
  }

  /*******
  Get email or userPrincipalName for invited users
  *******/
  public String getEmailOrUPN( SailPointContext context, Identity identity ) {

    plog.trace( "AADRL-GEOUPN-01::Entering Azure AD Rule Library - getEmailOrUPN" );
    String attributeName = "Email";

    String emailOrUPN = identity.getEmail();
    if ( emailOrUPN == null || emailOrUPN.isEmpty() ) {
      emailOrUPN = identity.getAttribute( "userPrincipalName" );
      attributeName = "UPN";
      if ( emailOrUPN == null || emailOrUPN.isEmpty() ) {
        emailOrUPN = "";
        attributeName = "Missing";
        toyotaLogger( context, "AADRL-GEOUPN-02::User: " + identity.getName() + " missing email and UPN.  Cannot invite user to Azure" );
      }
    }
    plog.trace( "AADRL-GEOUPN-03::Identity: " + identity.getName() + " " + attributeName + " :: " + emailOrUPN );
    plog.trace( "AADRL-GEOUPN-04::Leaving Azure AD Rule Library - getEmailOrUPN" );

    return emailOrUPN;
  }

 /***
  Set MFA Phone number via microsoft graph

  ***/
  public boolean setMfaPhoneWithMicrosoftGraph(Application app, String phoneNumber, String upn, String azureID) {


     plog.trace( "AADRL-SMFAPWMG-01::Entering Azure AD Rule Library - setMfaPhoneWithMicrosoftGraph" );

     // Format phone number to add space after +1 if present
     String formattedPhoneNumber = phoneNumber;
     if (Util.isNotNullOrEmpty(phoneNumber) && phoneNumber.startsWith("+1") && phoneNumber.length() > 2) {
       formattedPhoneNumber = "+1 " + phoneNumber.substring(2);
     }

     // Mask phone number for logging - show first 6 digits, mask the rest
     String maskedPhoneNumber = "";
     if (Util.isNotNullOrEmpty(formattedPhoneNumber)) {
       if (formattedPhoneNumber.length() >= 6) {
         maskedPhoneNumber = formattedPhoneNumber.substring(0, 6) + "****";
       } else {
         maskedPhoneNumber = formattedPhoneNumber + "****";
       }
     }
     plog.trace("AADRL-SMFAPWMG-01.1::Setting MFA phone number: " + maskedPhoneNumber + " for UPN: " + upn);     
     String azureADDomain = (String) app.getAttributeValue("domainName");
     String clientID = (String) app.getAttributeValue("clientID");
     String clientSecret = context.decrypt((String) app.getAttributeValue("clientSecret"));
     String resource = "https://graph.microsoft.com/beta/users/";
     String accessToken = getAccessToken(azureADDomain, resource, clientID, clientSecret);
     String url = resource + upn + "/authentication/phoneMethods";
     plog.trace("AADRL-SMFAPWMG-02::Update URL: " + url);
     HttpClient httpclient = HttpClients.createDefault();
     Boolean result = false;

    if (Util.isNotNullOrEmpty(phoneNumber)) {
      JSONObject payload = new JSONObject();
      payload.put("phoneNumber", phoneNumber);
      payload.put("phoneType", "Mobile");
      if ( plog.isTraceEnabled() ) {
        plog.trace("JSON Payload:\n\n" + payload.toString() + "\n\n");
      }
      StringEntity body = new StringEntity(payload.toString());
      HttpPost request = new HttpPost( url );
      request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
      request.setHeader(HttpHeaders.AUTHORIZATION, accessToken);
      request.setEntity(body);
      plog.trace("AADRL-SMFAPWMG-03::request:\n\n" + request + "\n\n");
      HttpResponse response = httpclient.execute(request);
      plog.trace("AADRL-SMFAPWMG-04::response\n\n" + response + "\n\n");
      int statuscode = response.getStatusLine().getStatusCode();
      plog.trace("AADRL-SMFAPWMG-05::Status Code " + statuscode);
      if (statuscode >= 200 && statuscode < 300) {
        plog.trace("Status Reason: " + response.getStatusLine().getReasonPhrase());
        result = true;
        HttpEntity entity = response.getEntity();
        if (entity != null) {
          String stuff = EntityUtils.toString(entity);
          plog.trace("AADRL-SMFAPWMG-06::Status Code: " + stuff);
        }
      } else {
        toyotaLogger( context, "AADRL-SMFAPWMG-07::An error occurred with MFA Enrollment Phone Method:: " + response+" for UPN:: "+upn+ " for number: " + maskedPhoneNumber);
      }
    }
    return result;
  }

  /***
  Add Authentication method - Email via microsoft graph

  ***/
  public boolean setMfaEmailWithMicrosoftGraph(Application app, String email, String upn, String azureID) {

    plog.trace( "AADRL-SMFAEWMG-01::Entering Azure AD Rule Library - setMfaEmailWithMicrosoftGraph" );

    // Mask email for logging - show first 4 chars before @, mask middle part, show full domain
    String maskedEmail = "";
    if (Util.isNotNullOrEmpty(email) && email.contains("@")) {
      String[] emailParts = email.split("@");
      String localPart = emailParts[0];
      String domain = emailParts[1];

      if (localPart.length() >= 4) {
        maskedEmail = localPart.substring(0, 4) + "****@" + domain;
      } else {
        maskedEmail = localPart + "****@" + domain;
      }
    } else if (Util.isNotNullOrEmpty(email)) {
      maskedEmail = email.substring(0, Math.min(email.length(), 4)) + "****";
    }    
    String azureADDomain = (String) app.getAttributeValue("domainName");
    String clientID = (String) app.getAttributeValue("clientID");
    String clientSecret = context.decrypt((String) app.getAttributeValue("clientSecret"));
    String resource = "https://graph.microsoft.com/beta/users/";
    String accessToken = getAccessToken(azureADDomain, resource, clientID, clientSecret);
    String url = resource + upn + "/authentication/emailMethods";
    plog.trace("AADRL-SMFAPWMG-02::Update URL: " + url);
    HttpClient httpclient = HttpClients.createDefault();
    Boolean result = false;

    if (Util.isNotNullOrEmpty(email)) {
      JSONObject payload = new JSONObject();
      payload.put("emailAddress", email);
      plog.trace("AADRL-SMFAPWMG-03::JSON Payload:\n\n" + payload.toString() + "\n\n");
      StringEntity body = new StringEntity(payload.toString());
      HttpPost request = new HttpPost( url );
      request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
      request.setHeader(HttpHeaders.AUTHORIZATION, accessToken);
      request.setEntity(body);
      plog.trace("AADRL-SMFAPWMG-04::request:\n\n" + request + "\n\n");
      HttpResponse response = httpclient.execute(request);
      plog.trace("response\n\n" + response + "\n\n");
      int statuscode = response.getStatusLine().getStatusCode();
      plog.trace("AADRL-SMFAPWMG-05::Status Code " + statuscode);
      if (statuscode >= 200 && statuscode < 300) {
        if ( plog.isTraceEnabled() ) {
          plog.trace("AADRL-SMFAPWMG-06::Status Reason: " + response.getStatusLine().getReasonPhrase());
        }
        result = true;
        HttpEntity entity = response.getEntity();
        if (entity != null) {
          String stuff = EntityUtils.toString(entity);
          plog.trace("AADRL-SMFAPWMG-07::Status Code: " + stuff);
        }
      } else {

        toyotaLogger( context, "AADRL-SMFAPWMG-08::An error occurred with MFA Enrollment Email Method:: " + response+" for UPN:: "+upn+ " for email: " + maskedEmail);
      }
    }
    return result;
  }
