  public static Boolean ValidateJWT(String jwtToken){
    Boolean expFlag = false;
    String[] split_string = jwtToken.split("\\.");
    String base64EncodedBody = split_string[1];
    Base64 base64Url = new Base64(true);
    String tokenBody = new String(base64Url.decode(base64EncodedBody));
    JSONObject jsonTokenObj = new JSONObject(tokenBody);
    long expTime = jsonTokenObj.getInt("exp");
    long instDate = Instant.now().getEpochSecond();
    Date updatedDate=new Date(expTime - (5 * 60));
    long fiveminutesbefore = updatedDate.getTime();
    if(instDate < fiveminutesbefore){
     expFlag = true;
    }else{
      expFlag = false;
    }
    return expFlag;
  }

  public static Map getAuthenticationStatus(SailPointContext context,Application app, String upn) {
    Map resultMap = new HashMap();
    String result="";
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AZAM-001 Entering Azure AD Rule Library - getAuthenticationStatus with "+app.getName()+" : "+upn );
    }
    List urlList=new ArrayList();
    Map searchFor=new HashMap();
    urlList.add("emailMethods");
    searchFor.put("emailMethods","emailAddress");
    urlList.add("phoneMethods");
    searchFor.put("phoneMethods","phoneNumber");
    try {
      String azureADDomain = (String) app.getAttributeValue("domainName");
      String clientID = (String) app.getAttributeValue("clientID");
      String clientSecret = context.decrypt((String) app.getAttributeValue("clientSecret"));
      String resource = "https://graph.microsoft.com/v1.0/users/";
      String accessToken = getAccessToken(azureADDomain, resource, clientID, clientSecret);
      HttpClient httpclient = HttpClients.createDefault();
      for(String urlEndPoint:urlList) {
        result="false";
        String url = resource + upn + "/authentication/" + urlEndPoint;
        if ( plog.isTraceEnabled() ) {
           plog.trace("AZAM-002 Update URL: " + url);
        }
        HttpGet request = new HttpGet( url );
        request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
        request.setHeader(HttpHeaders.AUTHORIZATION, accessToken);
        if ( plog.isTraceEnabled() ) {
          plog.trace("AZAM-003 request:\n" + request + "\n");
        }
        HttpResponse response = httpclient.execute(request);
        if ( plog.isTraceEnabled() ) {
          plog.trace("AZAM-004 response\n" + response + "\n");
        }
        int statuscode = response.getStatusLine().getStatusCode();
        if ( plog.isTraceEnabled() ) {
          plog.trace("AZAM-005 Status Code " + statuscode);
        }
        if (statuscode >= 200 && statuscode < 300) {
          BufferedReader br1 = new BufferedReader(new InputStreamReader(response.getEntity().getContent()));
          String s1 = br1.readLine();
          JSONObject jsonObject = new JSONObject(s1);
          JSONArray jsonArry = (JSONArray)jsonObject.get("value");
          if(jsonArry != null && jsonArry.length() > 0){
            String searchStr=searchFor.get(urlEndPoint);
            Object arrayElement=jsonArry.get(0);
            if(arrayElement instanceof JSONObject) {
              String value = normalizeToString(((JSONObject)arrayElement).get(searchStr));
              if ( plog.isTraceEnabled() ) {
                plog.trace("AZAM-006 searchStr="+searchStr+" value="+value);
              }
              if(Util.isNotNullOrEmpty(value)) {
                result = "true";
              }
            }
          }
        }
        else {
          toyotaLogger( context, "An error getting MFA emailAddress Status:: " + response+" UPN is :::"+upn);
        }
        if ( plog.isTraceEnabled() ) {
          plog.trace("AZAM-007 Adding ["+urlEndPoint+","+result+"]");
        }
        resultMap.put(urlEndPoint,result);
      }
    }
    catch (Exception ex) {
      plog.error("AZAM-099 Error in getMFAEmailStatus:"+ex.getClass().getName()+":"+ex.getMessage());
    }
    return resultMap;
  } 

  public boolean isAzureADGuestUser(ProvisioningPlan plan,SailPointContext context) throws GeneralException {
    if ( plog.isTraceEnabled() ) {
      plog.trace( "AADRL-ISAADGU-01::Entering Azure AD Rule Library - isAzureADGuestUser" );
      plog.trace( "AADRL-ISAADGU-02::Plan: " + plan.toXml() );
    }
    Identity identity=plan.getIdentity();
    boolean azuerADUserFlag=false;
    IdentityService idService=new IdentityService(context);
    List accReqList=plan.getAccountRequests();
    for(AccountRequest accReq:accReqList) {
      if(ProvisioningPlan.AccountRequest.Operation.Modify.equals(accReq.getOperation())){
        Application app=context.getObjectByName(Application.class, accReq.getApplication());
        if(null!=identity && accReq!=null && null!=app) {
          String nativeIdentity=accReq.getNativeIdentity();
          if(Util.isNotNullOrEmpty(nativeIdentity)){
            plog.trace("AADRL-ISAADGU-03::nativeIdentity:"+nativeIdentity);
            Link link=idService.getLink(identity,app, null, nativeIdentity);
            String userType=(String)link.getAttribute("userType");
            plog.trace("AADRL-ISAADGU-04::userType:"+userType);
            if("Guest".equals(userType)) {
              azuerADUserFlag=true;
              plog.trace("AADRL-ISAADGU-05::userType Guest:"+azuerADUserFlag);
            }
          } else {
            toyotaLogger( context, "AADRL-ISAADGU-06::Identity: " + identity.getName() + " missing nativeIdentity for Application: " + app.getName() );
          }
        }
      }
    }
    plog.trace( "AADRL-ISAADGU-07::userType:"+azuerADUserFlag);
    plog.trace( "AADRL-ISAADGU-08::Leaving Azure AD Rule Library - isAzureADGuestUser" );

    return azuerADUserFlag;
  }


  public ArrayList getaccountRequestsToRemove(String operation, AccountRequest accountRequest, sailpoint.object.Application application,
                                              Identity identity,SailPointContext context,ProvisioningPlan plan,String identityType) {
    Boolean linkedExistingAccount = false;
    ArrayList accountRequestsToRemove = new ArrayList();
    // Only work on Create Operations
    if (operation.equals("Create")) {
      linkedExistingAccount = createAzureGuestUser(context, accountRequest, application, identity);
      if (linkedExistingAccount) {
        accountRequestsToRemove.add(accountRequest);
      }

    } else if (operation.equals("Modify") && identityType.equalsIgnoreCase("supplier")) {
      // Work on Modify Operations
      linkedExistingAccount = updateAzureUser(context, plan, accountRequest, application, identity);
      if (linkedExistingAccount) {
        accountRequestsToRemove.add(accountRequest);
      }
    }
    return accountRequestsToRemove;
  }

  /**
  * removeTemporaryObjectId Remove a temporary Native Identity from Azure AD accounts used during
  * creation where Native Identity is required before it exists.
  * @param context The SailPointContext Object
  * @param accountRequest The current AccountRequest Object to be examined
  * @param application The Application Object being evaluated
  * @param identity The Identity Object being evaluated
  */
  public static void removeTemporaryObjectId( SailPointContext context, AccountRequest accountRequest, Application application, Identity identity ) {

    plog.trace( "AADRL-RTOID-01::Entering Azure AD Rule Library - removeTemporaryObjectId" );
    if ( accountRequest != null ) {
      String nativeIdentity = accountRequest.getNativeIdentity();
      if ( Util.isNotNullOrEmpty( nativeIdentity ) && nativeIdentity.equalsIgnoreCase( "??????" ) ) {
        accountRequest.setNativeIdentity( null );
        List attributeRequests = accountRequest.getAttributeRequests();
        List newAttributeRequests = new ArrayList();
        if ( attributeRequests != null && !attributeRequests.isEmpty() ) {
          for ( AttributeRequest attributeRequest : attributeRequests ) {
            String attributeName = attributeRequest.getName();
            if ( Util.isNotNullOrEmpty( attributeName ) && !attributeName.equalsIgnoreCase( "objectId" ) ) {
              newAttributeRequests.add( attributeRequest );
            }
          }
          accountRequest.setAttributeRequests( newAttributeRequests );
        }
      }
    }
    plog.trace( "AADRL-RTOID-02::Leaving Azure AD Rule Library - removeTemporaryObjectId" );

  }
  public static String normalizeToString(Object obj) {
    String rval="";
    if(obj==void || obj==null) {
      plog.debug("PTC-015 Entered normalizeToString with obj=null or void");
    } 
    else {
      plog.debug("PTC-016 Entered normalizeToString with obj:"+obj.getClass().getName()+"="+obj);
      if(obj instanceof String) {
        rval=(String)obj;
      }
      else if (obj instanceof List) {
        List rlist=(List)obj;
        if(rlist !=null && !rlist.isEmpty()) {
          rval=(rlist.get(0).toString());
        }
        else {
          rval=obj.toString();
        }
        plog.debug("PTC-017 Exiting normalizeToString with:"+rval);
      }
      else if(obj instanceof sailpoint.object.SailPointObject) {
        rval=obj.getName();
        plog.debug("PTC-018 Exiting normalizeToString with:"+rval);
      }
      else {
        rval=obj.toString();
        plog.debug("PTC-019 Exiting normalizeToString with:"+rval);
      }
    }
    return rval;
  }

  public String checkUserInRecycleBin( Identity identity, Application app, String URL ) throws Exception {

    String azureADDomain = app.getAttributeValue( "domainName" );
    String clientID = app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( app.getAttributeValue( "clientSecret" ) );
    String resource = app.getAttributeValue( "genericWebServiceBaseUrl" );
    String authToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    String token = "Bearer "+authToken;
    HttpClient httpclient = HttpClients.createDefault();
    HttpGet request = new HttpGet(URL);
    request.setHeader("Authorization", token);
    request.setHeader("Accept", "application/json");
    HttpResponse response = httpclient.execute(request);
    int statuscode = response.getStatusLine().getStatusCode();
    HttpEntity entity = response.getEntity();

    if (entity != null && statuscode==200) {
      String content = EntityUtils.toString( entity );
      JSONObject obj = new JSONObject( content );
      JSONArray valueList = obj.get("value");
      if (valueList.length()>0) {
        JSONObject valueObj = valueList.get(0);
        Map accountMap = new HashMap();
        accountMap = JsonUtil.toMap(valueObj.toString());
        String objectId = accountMap.get("id");
        return objectId;
      }
      else {
        return "failed";
      }
    }
    else {
      return "failed";
    }
  }

  public String getURLRecycleBin( Identity identity, Application app, String attributeName, String attributeValue){

    String URL = "https://graph.microsoft.com/v1.0/directory/deletedItems/"+"microsoft.graph.user?$filter=startsWith("+attributeName+",'"+attributeValue+"')";
    return URL;
  }
  public String restoreUser( String azureObjectId, Application app ) throws Exception {

    String azureADDomain = app.getAttributeValue( "domainName" );
    String clientID = app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( app.getAttributeValue( "clientSecret" ) );
    String resource = app.getAttributeValue( "genericWebServiceBaseUrl" );
    String authToken = getAccessToken( azureADDomain, resource, clientID, clientSecret );
    String token = "Bearer "+authToken;
    String URL = app.getAttributeValue( "recyclebinBaseUrl" ) +azureObjectId+"/restore";
    HttpClient httpclient = HttpClients.createDefault();
    HttpPost request = new HttpPost(URL);
    request.setHeader("Authorization", token);
    request.setHeader("Accept", "application/json");
    HttpResponse response = httpclient.execute(request);
    int statuscode = response.getStatusLine().getStatusCode();
    HttpEntity entity = response.getEntity();

    if (entity != null && statuscode==200) {
      return "success";
    }
    else {
      return "failed";
    }
  }

  /*Method to schedule workflow after 1 minute to execute the plan from after proviisoning rule*/

  public void createAzureModifyWorkflow(ProvisioningPlan afterProvPlan, String name) {

    plog.trace("AADRL-CAMW-001 :: Enterning Azure AD modify workflow method"); 
    String workflowName = "Modify Azure AD User Attributes";
    String requestName = "Run '" + workflowName + "' for: " + name;
    String requesterId = "spadmin";

    Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
    Identity id = context.getObjectByName(Identity.class, requesterId);

    plog.trace("AADRL-CAMW-002 :: id : "+id); 
    plog.trace("AADRL-CAMW-003 :: eventWorkflow : "+eventWorkflow);
    //Arguments to be passed to the Request Scheduler. 
    Attributes reqArgs = new Attributes();
    reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION, sailpoint.request.WorkflowRequestExecutor.DEFINITION_NAME);
    reqArgs.put(StandardWorkflowHandler.ARG_WORKFLOW, workflowName);
    reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_NAME, requestName);

    // Build a map of arguments to pass to the Workflow case when it launches. 
    Attributes wfArgs = new Attributes();
    wfArgs.put("identityName", name);
    wfArgs.put("workflow", eventWorkflow.getName());
    wfArgs.put("plan", afterProvPlan);
    reqArgs.putAll(wfArgs);

    //The workflow will be launched after one minute
    Calendar calendar = Calendar.getInstance();
    calendar.add(Calendar.MINUTE, 1);

    //Request Launcher will schedule the workflow reqeust. The Request object contains the properties of the request item. 
    Request req = new Request();
    RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
    req.setDefinition(reqdef);
    req.setOwner(id);
    req.setName(requestName);
    req.setEventDate(calendar.getTime());
    req.setAttributes( reqdef, reqArgs );
    RequestManager.addRequest(context, req);
    plog.trace("AADRL-CAMW-004:: Finished launching workflow for Azure AD Modify operation"); 
  }

  public String getInviteRedeemUrl(SailPointContext context, Application app, String email, String redirectionUrl) {
    String inviteUrl;
    plog.trace( "AADRL-GIRU-001 Entering Azure AD Rule Library - getInviteRedeemUrl with "+app.getName()+" : "+upn );

    HttpClient httpclient = HttpClients.createDefault();
    IdentityService identityService = new IdentityService(context);
    String azureADDomain = (String)app.getAttributeValue( "domainName" );
    String clientID = (String)app.getAttributeValue( "clientID" );
    String clientSecret = context.decrypt( (String)app.getAttributeValue( "clientSecret" ) );
    String graphUrl = "https://graph.microsoft.com/v1.0/invitations";
    String accessToken = getAccessToken( azureADDomain, graphUrl, clientID, clientSecret );
    JSONObject payload = new JSONObject();
    payload.put( "invitedUserEmailAddress", email );
    payload.put( "inviteRedirectUrl", redirectionUrl );
    StringEntity body = new StringEntity( payload.toString() );
    HttpPost request = new HttpPost( graphUrl );
    request.setHeader( HttpHeaders.CONTENT_TYPE, "application/json" );
    request.setHeader( HttpHeaders.AUTHORIZATION, accessToken );
    request.setEntity( body );
    HttpResponse response = httpclient.execute( request );
    int statuscode = response.getStatusLine().getStatusCode();
    if ( statuscode >= 200 && statuscode < 300 ) {
      plog.trace( "AADRL-GIRU-002 ::Status Reason: " + response.getStatusLine().getReasonPhrase() );
      HttpEntity entity = response.getEntity();
      if (entity != null) {
        String res = EntityUtils.toString(entity);
        JSONObject obj = new JSONObject( res );
        inviteUrl = obj.getString( "inviteRedeemUrl" );
      }
    } else {
      plog.error( "AADRL-GIRU-003 ::Invitation not created - Status Reason: " + response.getStatusLine().getReasonPhrase() );
    }
    return inviteUrl;
  }

