     request.setHeader(HttpHeaders.CONTENT_TYPE, "application/json");
     request.setHeader(HttpHeaders.AUTHORIZATION, accessToken);
     plog.trace("AADRL-RSS-003 :request:\n\n" + request + "\n\n");
     HttpResponse response = httpclient.execute(request);
     plog.trace("AADRL-RSS-004 :response\n\n" + response + "\n\n");
     int statuscode = response.getStatusLine().getStatusCode();
     plog.trace("AADRL-RSS-005 :Status Code " + statuscode);
       if (statuscode >= 200 && statuscode < 300) {
         plog.trace("AADRL-RSS-006 :Status Reason: " + response.getStatusLine().getReasonPhrase());
         result = true;
         HttpEntity entity = response.getEntity();
         if (entity != null) {
           String stuff = EntityUtils.toString(entity);
           plog.trace("AADRL-RSS-006 :Status Code: " + stuff);
        }
      }
    return result;
  }
  /*Schedule the workflow to execute the delete Plan*/
  public void scheduleAccountRequest(String name, String applicationName, ProvisioningPlan deletePlan, String workflowName,String caseName){

    String requesterId = "spadmin";
    Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
    Identity id = context.getObjectByName(Identity.class, requesterId);
    DateFormat dateFormat = new SimpleDateFormat("MM/dd/yyyy");
    Calendar calendar = Calendar.getInstance();
    calendar.add(Calendar.MINUTE, 5);
    Date futureTime = calendar.getTime();
    String launchTime = dateFormat.format(futureTime);
    caseName = caseName + "(" + launchTime + ")";
    Attributes reqArgs = new Attributes();
    reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION, sailpoint.request.WorkflowRequestExecutor.DEFINITION_NAME);
    reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_WORKFLOW, workflowName);
    reqArgs.put(sailpoint.workflow.StandardWorkflowHandler.ARG_REQUEST_NAME, caseName);
    reqArgs.put( "requestName", caseName );
    Attributes wfArgs = new Attributes();
    wfArgs.put("identityName",name);
    wfArgs.put("AzureADDeletePlan", deletePlan);
    wfArgs.put("appName",applicationName);
    wfArgs.put("workflow", eventWorkflow.getName());
    reqArgs.putAll(wfArgs);
    Request req = new Request();
    RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
    req.setDefinition(reqdef);
    req.setEventDate(futureTime);
    req.setOwner(id);
    req.setName(caseName);
    req.setAttributes( reqdef, reqArgs );
    RequestManager.addRequest(context, req);
  }

  /*Send Deleteplan for each account of Azure AD application for Schedule*/
  public void getAzureADDeletePlanSchedule(String identityName)
  {
    Identity identity =context.getObjectByName(Identity.class,identityName);
    ProvisioningPlan deletePlan=new ProvisioningPlan();
    deletePlan.setIdentity(identity);
    List acctreq;
    List azurelinks = identity.getLinks();
    if (azurelinks != null && azurelinks.size() > 0) {
      for(eachLink:azurelinks)
      {
        if (eachLink != null) {
          String applicationName=eachLink.getApplicationName();
          if(StringUtils.containsIgnoreCase(applicationName,"Azure"))
          {
            AccountRequest excAcctReq = new AccountRequest();
            String nativeIdentity = eachLink.getNativeIdentity() != null ? eachLink.getNativeIdentity(): eachLink.getAttribute("objectId");
            excAcctReq.setApplication(applicationName);
            excAcctReq.setNativeIdentity(nativeIdentity);
            excAcctReq.setOperation(AccountRequest.Operation.Delete);
            deletePlan.add(excAcctReq);
          }
        }
      }
      String workflowName = "Azure AD Delete AccountRequest Schedule";
      String caseName = "Run '" + workflowName + "' for: " + name;
      scheduleAccountRequest(identityName,"Azure",deletePlan,workflowName,caseName); 
    }
  }

  /*Remove Azure Account from CAPBlock group during Rehire*/
  public static ProvisioningPlan.AccountRequest removeAccountfromDisabledUserGroup(Application App,String nativeIdentity,Identity identity)
  {
    plog.trace("AADRL-AACB-001 Entering Azure AD Rule Library - to Remove User to CAPBlock ET ");
    ProvisioningPlan plan = new ProvisioningPlan();
    AccountRequest accountRequest = new AccountRequest();
    List attributeRequests= new ArrayList();
    String entValue=(String)App.getAttributeValue("disabledUserGroup");
    Filter filter = Filter.and(Filter.eq("application.id",App.getId()),Filter.eq("nativeIdentity",nativeIdentity),Filter.eq("aggregationState","Connected"),Filter.eq("value",entValue));
    QueryOptions queryOptions = new QueryOptions();
    queryOptions.add(filter);
    int count = context.countObjects(IdentityEntitlement.class,queryOptions);
    if ( count > 0 ) {
      plan.setIdentity(identity);
      accountRequest.setApplication(App.getName());
      accountRequest.setOperation(AccountRequest.Operation.Modify);
      accountRequest.setNativeIdentity(nativeIdentity);
      ProvisioningPlan.AttributeRequest roleRemove=new ProvisioningPlan.AttributeRequest();
      roleRemove.setName("groups");
      roleRemove.setOperation( ProvisioningPlan.Operation.Remove);
      roleRemove.setValue(entValue);
      attributeRequests.add(roleRemove);
      accountRequest.setAttributeRequests(attributeRequests);
      return accountRequest;
    }
    else
      return accountRequest;
  }
